/**
 * MedX typography theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Font scales, weights, and medical dashboard headings.
 */
const TYPOGRAPHY_TOKENS = Object.freeze({
  primary: { value: "theme-typography-primary", scope: "theme" },
  secondary: { value: "theme-typography-secondary", scope: "theme" },
  muted: { value: "theme-typography-muted", scope: "theme" },
  accent: { value: "theme-typography-accent", scope: "theme" },
  surface: { value: "theme-typography-surface", scope: "theme" },
});

const TYPOGRAPHY_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const TYPOGRAPHY_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const typographyRegistry = new Map();
const TYPOGRAPHY_listeners = new Set();
let TYPOGRAPHY_seq = 0;

function createTypographyId(prefix = "medx-theme-typography") {
  TYPOGRAPHY_seq += 1;
  return `${prefix}-${TYPOGRAPHY_seq}`;
}

function registerTypography(config = {}) {
  const entryId = config.id ?? createTypographyId();
  const preset = TYPOGRAPHY_PRESETS[config.preset ?? "default"] ?? TYPOGRAPHY_PRESETS.default;
  const token = TYPOGRAPHY_TOKENS[config.token ?? preset.token] ?? TYPOGRAPHY_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: TYPOGRAPHY_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  typographyRegistry.set(entryId, entry);
  notifyTypographyListeners("register", entry);
  return entry;
}

function updateTypography(id, patch = {}) {
  const entry = typographyRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyTypographyListeners("update", entry);
  return entry;
}

function resolveTypography(id) {
  const entry = typographyRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listTypographyEntries(filter = {}) {
  let items = Array.from(typographyRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onTypographyEvent(listener) {
  TYPOGRAPHY_listeners.add(listener);
  return () => TYPOGRAPHY_listeners.delete(listener);
}

function notifyTypographyListeners(type, entry) {
  for (const listener of TYPOGRAPHY_listeners) {
    try {
      listener({ type, entry, registrySize: typographyRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:typography] listener error", err.message);
    }
  }
}

function getTypographyMetrics() {
  const items = listTypographyEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(TYPOGRAPHY_TOKENS).length,
    presets: Object.keys(TYPOGRAPHY_PRESETS).length,
  };
}

async function runMedxTypography() {
  console.log("[medx:ui:theme:typography] runtime initialized");
  console.log(`[medx:ui:theme:typography] tokens=${Object.keys(TYPOGRAPHY_TOKENS).length} presets=${Object.keys(TYPOGRAPHY_PRESETS).length}`);

  const events = [];
  onTypographyEvent((e) => events.push(e.type));

  const domains = Object.keys(TYPOGRAPHY_SUPPLY_CHAIN);
  const presets = Object.keys(TYPOGRAPHY_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerTypography({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/typography" },
    });
  }

  const first = listTypographyEntries()[0];
  if (first) updateTypography(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getTypographyMetrics();
  const resolved = first ? resolveTypography(first.id) : null;

  console.log(`[medx:ui:theme:typography] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:typography] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:typography] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:typography] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:typography] bootstrap complete");
}

module.exports = runMedxTypography;
